+        fn snapshot_flex(
+            constraints: &[Constraint],
+            dir: Direction,
+            width: u16,
+            height: u16,
+        ) -> String {
+            let flex = Flex::default()
+                .direction(dir)
+                .constraints(constraints.iter().copied());
+            let rects = flex.split(Rect::new(0, 0, width, height));
+            let mut out = format!(
+                "Flex {:?} {}x{} ({} constraints)\n",
+                dir,
+                width,
+                height,
+                constraints.len()
+            );
+            for (i, r) in rects.iter().enumerate() {
+                out.push_str(&format!(
+                    "  [{}] x={} y={} w={} h={}\n",
+                    i, r.x, r.y, r.width, r.height
+                ));
+            }
+            let total: u16 = rects
+                .iter()
+                .map(|r| match dir {
+                    Direction::Horizontal => r.width,
+                    Direction::Vertical => r.height,
+                })
+                .sum();
+            out.push_str(&format!("  total={}\n", total));
+            out
+        }
+
+        fn snapshot_grid(
+            rows: &[Constraint],
+            cols: &[Constraint],
+            areas: &[(&str, GridArea)],
+            width: u16,
+            height: u16,
+        ) -> String {
+            let mut grid = Grid::new()
+                .rows(rows.iter().copied())
+                .columns(cols.iter().copied());
+            for &(name, area) in areas {
+                grid = grid.area(name, area);
+            }
+            let layout = grid.split(Rect::new(0, 0, width, height));
+
+            let mut out = format!(
+                "Grid {}x{} ({}r x {}c)\n",
+                width,
+                height,
+                rows.len(),
+                cols.len()
+            );
+            for r in 0..rows.len() {
+                for c in 0..cols.len() {
+                    let rect = layout.cell(r, c);
+                    out.push_str(&format!(
+                        "  [{},{}] x={} y={} w={} h={}\n",
+                        r, c, rect.x, rect.y, rect.width, rect.height
+                    ));
+                }
+            }
+            for &(name, _) in areas {
+                if let Some(rect) = layout.area(name) {
+                    out.push_str(&format!(
+                        "  area({}) x={} y={} w={} h={}\n",
+                        name, rect.x, rect.y, rect.width, rect.height
+                    ));
+                }
+            }
+            out
+        }
